(window.webpackJsonp=window.webpackJsonp||[]).push([[15],{642:function(n,t){n.exports='\x3c!-- \ntitle: 01-CPP入门\nsort: \n--\x3e \n\n# C++入门\n\n## 第一个C++程序\n\n```c++\n#include<iostream>\nusing namespace std;\n\nint main()\n{\n\n\tcout << "Hello world" << endl;\n\n\tsystem("pause");\n\n\treturn 0;\n}\n```\n\n## 入门\n\n```cpp\n// 字符串\nstring str = "hello world";\ncout << str << endl;\t\t// 输出\n// 输入\ncout << "请输入：" << endl;\ncin >> str;\ncout << str << endl;\n// 三目\nc = a > b ? a : b;\n// 结构体\nstruct student {\n\tstring name;  \n\tint age;      \n\tint score;    \n};\n// 结构体数组\nstruct student arr[3]=\n{\n\t{"张三",18,80 },\n\t{"李四",19,60 },\n\t{"王五",20,70 }\n};\n// 结构体指针\nstruct student * p = &arr[0];\np->score=75;\n```\n\n## 面向对象\n\n```cpp\n#include <stdio.h>\n\nclass ClassHi {\npublic:\n  ClassHi() {\n    button = false;\n    f = stdout;\n  }\n  ClassHi(FILE *ff) {\n    button = false;\n    f = ff;\n  }\n  void print(char *s) { fprintf(f, "%s\\n", s); }\n  void on() { button = true; }\n  void off() { button = false; }\n\nprivate:\n  bool button;\n  FILE *f;\n};\n\nint main(){\n  ClassHi hi;\n  hi.print((char*)"Hi~Class");\n  ClassHi hi2(stderr);\n  hi.print((char*)"Hi~Class");\n}\n```\n\n'}}]);